1	/* ============================================
2	   习惯管理 - 天子日课
3	   ============================================ */
4	
5	/* ---- 页面头部 ---- */
6	.page-header {
7	  display: flex;
8	  justify-content: space-between;
9	  align-items: flex-start;
10	  margin-bottom: var(--space-xl);
11	}
12	
13	.add-btn {
14	  width: 72rpx;
15	  height: 72rpx;
16	  border-radius: var(--radius-full);
17	  background: var(--color-accent);
18	  color: var(--color-text-inverse);
19	  display: flex;
20	  align-items: center;
21	  justify-content: center;
22	  font-size: 44rpx;
23	  font-weight: 300;
24	  line-height: 1;
25	  transition: opacity 0.2s;
26	}
27	
28	.add-btn:active {
29	  opacity: 0.8;
30	}
31	
32	/* ---- 分类管理入口 ---- */
33	.domain-manager-entry {
34	  display: flex;
35	  align-items: center;
36	  gap: var(--space-md);
37	  padding: var(--space-lg) var(--space-md);
38	  margin-bottom: var(--space-lg);
39	  background: var(--color-card);
40	  border: 1rpx solid var(--color-border);
41	  border-radius: var(--radius-lg);
42	  transition: all 0.2s;
43	}
44	
45	.domain-manager-entry:active {
46	  background: var(--color-card-hover);
47	  border-color: var(--color-border-light);
48	}
49	
50	.domain-manager-entry-bar {
51	  width: 6rpx;
52	  height: 32rpx;
53	  background: var(--color-accent);
54	  border-radius: 3rpx;
55	  flex-shrink: 0;
56	}
57	
58	.domain-manager-entry-text {
59	  flex: 1;
60	  font-size: var(--text-md);
61	  font-weight: 500;
62	  color: var(--color-text-primary);
63	  letter-spacing: 0.02em;
64	}
65	
66	.domain-manager-entry-arrow {
67	  font-size: var(--text-xl);
68	  color: var(--color-text-muted);
69	  flex-shrink: 0;
70	  line-height: 1;
71	}
72	
73	/* ---- 领域标题 ---- */
74	.domain-title {
75	  display: block;
76	  font-size: var(--text-sm);
77	  color: var(--color-text-muted);
78	  margin: var(--space-xl) 0 var(--space-md);
79	  padding-left: var(--space-md);
80	  border-left: 3rpx solid var(--color-accent);
81	}
82	
83	.domain-title-row {
84	  display: flex;
85	  align-items: center;
86	  gap: 8rpx;
87	  margin-top: 24rpx;
88	  margin-bottom: 8rpx;
89	}
90	
91	/* ---- 习惯卡片 ---- */
92	.habit-card {
93	  background: var(--color-card);
94	  border: 1rpx solid var(--color-border);
95	  border-radius: var(--radius-md);
96	  padding: var(--space-lg);
97	  margin-bottom: var(--space-sm);
98	  transition: all 0.2s ease;
99	}
100	
101	.habit-card.inactive {
102	  opacity: 0.45;
103	}
104	
105	.habit-info {
106	  margin-bottom: var(--space-md);
107	}
108	
109	.habit-name {
110	  display: block;
111	  font-size: var(--text-md);
112	  font-weight: 500;
113	  color: var(--color-text-primary);
114	  letter-spacing: 0.02em;
115	}
116	
117	.habit-desc {
118	  display: block;
119	  font-size: var(--text-xs);
120	  color: var(--color-text-muted);
121	  margin-top: var(--space-xs);
122	}
123	
124	.habit-meta {
125	  display: block;
126	  font-size: var(--text-xs);
127	  color: var(--color-text-muted);
128	  margin-top: var(--space-sm);
129	  font-feature-settings: "tnum";
130	}
131	
132	/* ---- 卡片操作按钮 ---- */
133	.habit-actions {
134	  display: flex;
135	  gap: var(--space-sm);
136	}
137	
138	.habit-actions .action-btn {
139	  padding: var(--space-sm) var(--space-xl);
140	  min-height: 88rpx;
141	  border-radius: var(--radius-xs);
142	  font-size: var(--text-xs);
143	  font-weight: 500;
144	  background: var(--color-surface);
145	  color: var(--color-text-secondary);
146	  border: 1rpx solid var(--color-border);
147	  transition: all 0.2s;
148	  display: flex;
149	  align-items: center;
150	  justify-content: center;
151	}
152	
153	.habit-actions .action-btn:active {
154	  background: var(--color-border);
155	}
156	
157	.habit-actions .action-btn.danger {
158	  background: var(--color-danger-subtle);
159	  color: var(--color-danger);
160	  border-color: transparent;
161	}
162	
163	.habit-actions .action-btn.danger:active {
164	  opacity: 0.8;
165	}
166	
167	.habit-actions .action-btn.disabled {
168	  opacity: 0.4;
169	}
170	
171	/* ============================================
172	   分类管理 - 重设计
173	   ============================================ */
174	
175	/* ---- 弹窗顶饰 ---- */
176	.domain-manager-accent {
177	  width: 48rpx;
178	  height: 4rpx;
179	  background: var(--color-accent);
180	  border-radius: 2rpx;
181	  margin: 0 auto var(--space-xl);
182	  opacity: 0.6;
183	}
184	
185	/* ---- 弹窗头部 ---- */
186	.modal-header-row {
187	  display: flex;
188	  justify-content: space-between;
189	  align-items: center;
190	  margin-bottom: var(--space-xl);
191	}
192	
193	.modal-header-row .modal-title {
194	  margin-bottom: 0;
195	}
196	
197	.modal-add-btn {
198	  display: flex;
199	  align-items: center;
200	  gap: var(--space-xs);
201	  font-size: var(--text-sm);
202	  font-weight: 500;
203	  color: var(--color-accent);
204	  padding: var(--space-xs) var(--space-md);
205	  border: 1rpx solid var(--color-accent-subtle);
206	  border-radius: var(--radius-sm);
207	  background: var(--color-accent-subtle);
208	}
209	
210	/* ---- 分类列表项（卡片式） ---- */
211	.domain-item {
212	  display: flex;
213	  align-items: center;
214	  gap: var(--space-md);
215	  padding: var(--space-lg) var(--space-md);
216	  margin-bottom: var(--space-sm);
217	  background: var(--color-surface);
218	  border: 1rpx solid var(--color-border);
219	  border-radius: var(--radius-md);
220	  transition: all 0.2s;
221	}
222	
223	.domain-item:active {
224	  background: var(--color-card-hover);
225	}
226	
227	.domain-item-bar {
228	  width: 6rpx;
229	  height: 40rpx;
230	  border-radius: 3rpx;
231	  flex-shrink: 0;
232	}
233	
234	.domain-item-icon {
235	  font-size: 36rpx;
236	  flex-shrink: 0;
237	  line-height: 1;
238	}
239	
240	.domain-item-name {
241	  flex: 1;
242	  font-size: var(--text-md);
243	  color: var(--color-text-primary);
244	  font-weight: 500;
245	}
246	
247	.domain-item-tag {
248	  font-size: var(--text-xs);
249	  color: var(--color-text-muted);
250	  background: var(--color-bg);
251	  padding: var(--space-xs) var(--space-sm);
252	  border-radius: var(--radius-xs);
253	  flex-shrink: 0;
254	}
255	
256	.domain-item-actions {
257	  display: flex;
258	  gap: var(--space-sm);
259	  flex-shrink: 0;
260	}
261	
262	.domain-item-action {
263	  width: 72rpx;
264	  height: 72rpx;
265	  border-radius: var(--radius-full);
266	  display: flex;
267	  align-items: center;
268	  justify-content: center;
269	  font-size: 24rpx;
270	  transition: all 0.2s;
271	}
272	
273	.domain-item-action.edit {
274	  background: var(--color-accent-subtle);
275	  color: var(--color-accent);
276	}
277	
278	.domain-item-action.delete {
279	  background: var(--color-danger-subtle);
280	  color: var(--color-danger);
281	}
282	
283	.domain-item-action:active {
284	  transform: scale(0.88);
285	}
286	
287	.domain-item-action.disabled {
288	  opacity: 0.4;
289	}
290	
291	/* ---- 弹窗关闭按钮 ---- */
292	.domain-close-btn {
293	  display: flex;
294	  align-items: center;
295	  justify-content: center;
296	  padding: var(--space-lg) 0 var(--space-xs);
297	  font-size: var(--text-sm);
298	  color: var(--color-text-muted);
299	  letter-spacing: 0.04em;
300	  transition: color 0.2s;
301	}
302	
303	.domain-close-btn:active {
304	  color: var(--color-text-secondary);
305	}
306	
307	/* ---- 表单区块 ---- */
308	.form-section {
309	  margin-bottom: var(--space-xl);
310	}
311	
312	.form-section-title {
313	  display: block;
314	  font-size: var(--text-sm);
315	  font-weight: 500;
316	  color: var(--color-text-secondary);
317	  margin-bottom: var(--space-md);
318	  letter-spacing: 0.02em;
319	}
320	
321	/* ---- Emoji 选择器（双行横滚） ---- */
322	.emoji-picker-rows {
323	  display: flex;
324	  flex-direction: column;
325	  gap: var(--space-sm);
326	}
327	
328	.emoji-row {
329	  display: flex;
330	  gap: var(--space-sm);
331	  overflow-x: auto;
332	  overflow-y: hidden;
333	  padding: var(--space-xs) 0;
334	  -webkit-overflow-scrolling: touch;
335	  scrollbar-width: none;
336	}
337	
338	.emoji-row::-webkit-scrollbar {
339	  display: none;
340	}
341	
342	.emoji-pill {
343	  width: 76rpx;
344	  height: 76rpx;
345	  border-radius: var(--radius-md);
346	  background: var(--color-surface);
347	  border: 1.5rpx solid var(--color-border);
348	  display: flex;
349	  align-items: center;
350	  justify-content: center;
351	  font-size: 34rpx;
352	  flex-shrink: 0;
353	  transition: all 0.2s;
354	  box-sizing: border-box;
355	}
356	
357	.emoji-pill:active {
358	  transform: scale(0.92);
359	  border-color: var(--color-accent);
360	}
361	
362	.emoji-pill.selected {
363	  background: var(--color-accent-subtle);
364	  border-color: var(--color-accent);
365	  transform: scale(1.08);
366	}
367	
368	/* ---- SVG 图标选择器 ---- */
369	.icon-picker-grid {
370	  display: flex;
371	  flex-direction: row;
372	  flex-wrap: wrap;
373	  gap: var(--space-sm);
374	}
375	
376	.icon-pill {
377	  width: 88rpx;
378	  height: 88rpx;
379	  border-radius: var(--radius-md);
380	  background: var(--color-surface);
381	  border: 2rpx solid transparent;
382	  display: flex;
383	  align-items: center;
384	  justify-content: center;
385	  flex-shrink: 0;
386	  transition: all 0.2s;
387	  box-sizing: border-box;
388	}
389	
390	.icon-pill:active {
391	  transform: scale(0.92);
392	  border-color: var(--color-accent);
393	}
394	
395	.icon-pill.selected {
396	  border-color: var(--color-accent);
397	  transform: scale(1.08);
398	  background: var(--color-card);
399	}
400	
401	/* ---- 颜色选择器（呼吸感） ---- */
402	.color-picker-grid {
403	  display: flex;
404	  gap: var(--space-md);
405	  flex-wrap: wrap;
406	}
407	
408	.color-swatch {
409	  width: 68rpx;
410	  height: 68rpx;
411	  border-radius: var(--radius-full);
412	  border: 2rpx solid transparent;
413	  display: flex;
414	  align-items: center;
415	  justify-content: center;
416	  transition: all 0.3s;
417	  box-sizing: border-box;
418	}
419	
420	.color-swatch-inner {
421	  width: 48rpx;
422	  height: 48rpx;
423	  border-radius: var(--radius-full);
424	  transition: all 0.3s;
425	}
426	
427	.color-swatch.selected {
428	  border-color: var(--color-accent);
429	  transform: scale(1.1);
430	}
431	
432	.color-swatch.selected .color-swatch-inner {
433	  width: 40rpx;
434	  height: 40rpx;
435	  filter: drop-shadow(0 0 8rpx var(--color-accent));
436	  animation: color-breathe 2s ease-in-out infinite;
437	}
438	
439	@keyframes color-breathe {
440	  0%, 100% {
441	    filter: drop-shadow(0 0 4rpx var(--color-accent));
442	  }
443	  50% {
444	    filter: drop-shadow(0 0 16rpx var(--color-accent));
445	  }
446	}
447	
448	/* ---- 领域选择器指示器 ---- */
449	.domain-picker-indicator {
450	  width: 16rpx;
451	  height: 16rpx;
452	  border-radius: 50%;
453	  flex-shrink: 0;
454	  margin-top: 4rpx;
455	}
